+        let diag = d.diagnostic_snapshot();
+        assert!(diag.is_clean());
+        assert!(diag.leaks.is_empty());
+        assert_eq!(diag.memory_report.live_handles, 0);
+        assert!(diag.dispatch_count > 0);
+    }
